#include "RotateRun.hpp"using namespace debrisys;void RotateRun::run(){    mTurn = mTuRn->getTurn();    switch (mDirection)    {        case ERotDire::LEFT :            rotateLeft();            break;        case ERotDire::RIGHT :            rotateRight();            break;        default :            break;    }}void RotateRun::rotateLeft(){    mLeftMotor.setPower(-mPOWER - mTurn);    mRightMotor.setPower(mPOWER + mTurn);}void RotateRun::rotateRight(){    mLeftMotor.setPower(mPOWER + mTurn);    mRightMotor.setPower(-mPOWER - mTurn);}